#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, P; scanf("%d", &N);
        int arr[16];
        for(int i=0;i<N;i++) scanf("%d", &arr[i]);
        scanf("%d", &P);
        for(int i=P;i<N-1;i++) arr[i]=arr[i+1];
        for(int i=0;i<N-1;i++){
            if(i) printf(" ");
            printf("%d", arr[i]);
        }
        if(T) printf("\n");
    }
    return 0;
}

